class Solution:
    def getXORSum(self, arr1, arr2):
        # independent per-bit parity count (does not assume the AND-over-XOR identity)
        res = 0
        for bit in range(31):
            m = 1 << bit
            c1 = sum(1 for a in arr1 if a & m)
            c2 = sum(1 for b in arr2 if b & m)
            # bit set in odd number of pairs <=> c1*c2 is odd
            if (c1 * c2) & 1:
                res |= m
        return res

